class TicTacToe:
    """Class for the Tic-Tac-Toe game."""
    def __init__(self):
        self.board = [[' ' for _ in range(3)] for _ in range(3)]
        self.current_player = Player.X

    def print_board(self):
        """Print the current state of the board."""
        print(' ' + self.board[0][0] + ' | ' + self.board[0][1] + ' | ' + self.board[0][2])
        print('-----------')
        print(' ' + self.board[1][0] + ' | ' + self.board[1][1] + ' | ' + self.board[1][2])
        print('-----------')
        print(' ' + self.board[2][0] + ' | ' + self.board[2][1] + ' | ' + self.board[2][2])

    def is_valid_move(self, row: int, col: int) -> bool:
        """Check if a move is valid."""
        return 0 <= row < 3 and 0 <= col < 3 and self.board[row][col] == ' '

    def make_move(self, row: int, col: int) -> None:
        """Make a move on the board."""
        if self.is_valid_move(row, col):
            self.board[row][col] = self.current_player.value
            self.current_player = Player.O if self.current_player == Player.X else Player.X
        else:
            raise ValueError("Invalid move")

    def check_winner(self) -> Player | None:
        """Check if there is a winner."""
        # Check rows
        for row in self.board:
            if row[0] == row[1] == row[2] != ' ':
                return Player.X if row[0] == 'X' else Player.O

        # Check columns
        for col in range(3):
            if self.board[0][col] == self.board[1][col] == self.board[2][col] != ' ':
                return Player.X if self.board[0][col] == 'X' else Player.O

        # Check diagonals
        if self.board[0][0] == self.board[1][1] == self.board[2][2] != ' ':
            return Player.X if self.board[0][0] == 'X' else Player.O
        if self.board[0][2] == self.board[1][1] == self.board[2][0] != ' ':
            return Player.X if self.board[0][2] == 'X' else Player.O

        return None

    def is_draw(self) -> bool:
        """Check if the game is a draw."""
        return all(cell != ' ' for row in self.board for cell in row)

